const urlString = $.input.urls || '';
const urls = urlString.split(',').map(u => u.trim()).filter(u => u.startsWith('http'));
return { urls, urlCount: urls.length };

const urls = $.steps.parseUrls.output.urls;
const iterations = $.steps.scrapeAll.response.iterations || [];

let allData = '';
let successCount = 0;
iterations.forEach((iter, i) => {
  const url = urls[i] || 'Unknown';
  const resp = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : {};
  const md = resp.markdown || '';

  allData += '=== PAGE ' + (i + 1) + ' ===\n';
  allData += 'URL: ' + url + '\n';
  allData += 'Title: ' + (resp.metadata && resp.metadata.title ? resp.metadata.title : 'Unknown') + '\n';
  allData += 'Content:\n' + md.slice(0, 3000) + '\n\n';
  if (md.length > 0) successCount++;
});

return { allData, successCount, totalUrls: urls.length };

const d = $.steps.compileScrapedData.output;
const goal = $.input.extractionGoal;

let prompt = 'You are a web scraping data extraction specialist. Extract structured data from the scraped webpages below.\n\n';
prompt += 'EXTRACTION GOAL: ' + goal + '\n';
prompt += 'PAGES SCRAPED: ' + d.successCount + '/' + d.totalUrls + '\n\n';
prompt += 'SCRAPED CONTENT:\n' + d.allData + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract the requested data from each page\n';
prompt += '- Organize results per-page and as a combined summary\n';
prompt += '- Identify any patterns or insights across pages\n';
prompt += '- Use Slack mrkdwn formatting in the summary\n';
prompt += '- Slack rules: use *bold* (NOT **bold**). No markdown tables. No # headings.\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "pages": [\n';
prompt += '    {\n';
prompt += '      "url": "page url",\n';
prompt += '      "title": "page title",\n';
prompt += '      "extractedData": { "field1": "value1" },\n';
prompt += '      "summary": "one-line summary"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "combinedInsights": "cross-page analysis in Slack mrkdwn",\n';
prompt += '  "totalItemsExtracted": 0,\n';
prompt += '  "dataQuality": "high|medium|low"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { pages: [], combinedInsights: raw, totalItemsExtracted: 0, dataQuality: 'unknown' }; }

const ai = $.steps.parseAI.output;
const urlCount = $.steps.parseUrls.output.urlCount;
const successCount = $.steps.compileScrapedData.output.successCount;
const goal = $.input.extractionGoal;

const qualityEmoji = ai.dataQuality === 'high' ? ':large_green_circle:' : ai.dataQuality === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Ultimate Scraper Results' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Extraction Goal:*\n' + goal },
  { type: 'mrkdwn', text: '*Pages Scraped:*\n' + successCount + '/' + urlCount }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Items Extracted:*\n' + (ai.totalItemsExtracted || 0) },
  { type: 'mrkdwn', text: '*Data Quality:*\n' + qualityEmoji + ' ' + (ai.dataQuality || 'unknown') }
] });
blocks.push({ type: 'divider' });

const pages = ai.pages || [];
pages.slice(0, 5).forEach((p, i) => {
  let pageText = '*Page ' + (i + 1) + ':* <' + (p.url || '#') + '|' + (p.title || 'Untitled').slice(0, 50) + '>\n';
  pageText += p.summary || 'No summary';
  if (p.extractedData) {
    const keys = Object.keys(p.extractedData).slice(0, 5);
    keys.forEach(k => {
      const val = String(p.extractedData[k]).slice(0, 100);
      pageText += '\n  *' + k + ':* ' + val;
    });
  }
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: pageText.slice(0, 1800) } });
});

blocks.push({ type: 'divider' });

if (ai.combinedInsights) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Cross-Page Insights:*\n' + (ai.combinedInsights || '').slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Firecrawl + Claude AI' }] });

const fallback = 'Scraped ' + successCount + ' pages, extracted ' + (ai.totalItemsExtracted || 0) + ' items';
return { blocks, fallback };
